import mlx.core as mx
import mlx.nn as nn

class MergeableLoRALinear(nn.Module):
    def __init__(self, in_features: int, out_features: int, rank: int = 16,
                 alpha: float = 32.0, bias: bool = False, merged: bool = False):
        super().__init__()
        self.rank = rank
        self.scale = alpha / rank
        self.merged = merged
        self.weight = mx.zeros((out_features, in_features))  # base weight
        if bias:
            self.bias = mx.zeros((out_features,))
        # LoRA matrices: A is random, B is zero (standard LoRA init)
        self.lora_A = mx.random.normal((rank, in_features)) * (1.0 / rank) ** 0.5
        self.lora_B = mx.zeros((out_features, rank))

    @property
    def effective_weight(self):
        return self.weight + self.scale * (self.lora_B @ self.lora_A)

    def merge(self):
        """Fold LoRA into base weight for efficient deployment."""
        if not self.merged:
            self.weight = self.weight + self.scale * (self.lora_B @ self.lora_A)
            self.lora_A = mx.zeros_like(self.lora_A)
            self.lora_B = mx.zeros_like(self.lora_B)
            self.merged = True

    def unmerge(self, original_weight: mx.array):
        """Restore base weight (requires keeping original)."""
        if self.merged:
            self.weight = original_weight
            self.merged = False

    def __call__(self, x: mx.array) -> mx.array:
        if self.merged:
            out = x @ self.weight.T
        else:
            out = x @ self.weight.T + self.scale * (x @ self.lora_A.T) @ self.lora_B.T
        if hasattr(self, 'bias'):
            out = out + self.bias
        return out

