# Useful for numerically stable ops where the naive gradient overflows.

def log_sum_exp(x, axis=-1):
    m = mx.max(x, axis=axis, keepdims=True)
    return mx.log(mx.sum(mx.exp(x - m), axis=axis)) + m.squeeze(axis)

# This avoids overflow by subtracting the max before exp.
# mx.grad(log_sum_exp) works correctly since all ops are differentiable.

mx.checkpoint(fn)(*args) wraps fn so that during the forward pass, intermediate activations are NOT stored for backward. During the backward pass, the forward pass is RE-RUN to recompute intermediates. Trade-off: saves memory (O(1) activations per layer instead of O(T)) at ~33% compute overhead. Use when training deep models that OOM on Apple Silicon — particularly transformers with long sequences. Example:

for layer in self.layers:
    x = mx.checkpoint(layer)(x)

from functools import partial
import mlx.core as mx

class GradCheckpointedStack(nn.Module):
    def __init__(self, layers):
        super().__init__()
        self.layers = layers

    def __call__(self, x, **kwargs):
        for layer in self.layers:
            # Checkpoint: recompute forward during backward, don't store activations
            x = mx.checkpoint(partial(layer, **kwargs))(x)
        return x

# Method: assign the same weight tensor to both layers after init
class TiedLinear(nn.Module):
    def __init__(self, dim):
        super().__init__()
        self.encoder = nn.Linear(dim, dim)
        self.decoder = nn.Linear(dim, dim, bias=False)
        # Tie weights: decoder shares encoder's weight
        self.decoder.weight = self.encoder.weight

    def __call__(self, x):
        h = self.encoder(x)
        return self.decoder(h)

# Gradients flow to self.encoder.weight from both paths automatically.

